  private readonly cdr = inject(ChangeDetectorRef);
  private readonly clientPermissionsService = inject(ClientPermissionsService);
  readonly qaTools = inject(QAToolsService);
  private readonly translate = inject(TranslateService);
  private readonly languageService = inject(LanguageService);

  @ViewChild('main') mainTemplate!: TemplateRef<unknown>;

  /**
   * Static tab structure - defines hierarchy, labels, and routes
   * Permissions are pulled from CLIENT_ADMIN_FEATURES config
   */
  private baseClientTabs: TypedTabConfig<ClientFeatureId>[] = [];

  /**
   * Computed signal that filters tabs based on user permissions.
   * Hides parent tabs if they have no visible children.
   * Reactive - updates when permissions change.
   */
  readonly clientTabs = computed(() => {
    this.languageService.currentLanguage();
    return this.filterTabsByPermissions(this.baseClientTabs);
  });

  private readonly router = inject(Router);
  private readonly activatedRoute = inject(ActivatedRoute);
  private readonly destroyRef = inject(DestroyRef);
  readonly detailsService = inject(EntityDetailsService);
  readonly isContentScrollable = signal<boolean>(false);

  @HostBinding('class.content-scrollable-inactive')
  get contentScrollableActive(): boolean {
    return !this.isContentScrollable();
  }

  ngAfterViewInit() {
    this.applyTemplateToTabs(this.baseClientTabs, this.mainTemplate);
    this.cdr.detectChanges();
  }

  private applyTemplateToTabs(
    tabs: TypedTabConfig<ClientFeatureId>[],
    template: TemplateRef<unknown>,
  ) {
    for (const tab of tabs) {
      tab.template = template;
      if (tab.children !== undefined && tab.children.length > 0) {
        this.applyTemplateToTabs(tab.children, template);
      }
    }
  }

  /**
   * Filters tabs based on permissions.
   * Returns only tabs the user has access to.
   * Hides parent tabs if all children are hidden.
   */
  private filterTabsByPermissions(
    tabs: TypedTabConfig<ClientFeatureId>[],
  ): TypedTabConfig<ClientFeatureId>[] {
    return tabs
      .map((tab) => {
        const config = CLIENT_ADMIN_FEATURES[tab.id];
        const hasPermission = this.clientPermissionsService.canAccessFeature(
          'permissions' in config ? config.permissions : undefined,
        );

        // If tab has no permission, exclude it
        if (!hasPermission) {
          return null;
        }

        // If tab has children, recursively filter them
        if (tab.children !== undefined && tab.children.length > 0) {
          const filteredChildren = this.filterTabsByPermissions(tab.children);

          // If all children are hidden, hide parent too
          if (filteredChildren.length === 0) {
            return null;
          }

          // Return tab with filtered children
          return {
            ...tab,
            children: filteredChildren,
          };
        }

        return tab;
      })
      .filter((tab): tab is TypedTabConfig<ClientFeatureId> => tab !== null);
  }

  onTabChange() {
    this.detailsService.closeDetailsPanel();
  }

  ngOnInit(): void {
    this.baseClientTabs = this.buildClientTabs();
    // Function to get scrollable state from route
    const getScrollableState = (route: ActivatedRoute): boolean => {
      let currentRoute = route;
      while (currentRoute.firstChild) {
        currentRoute = currentRoute.firstChild;
      }
      const routeData: Data = currentRoute.snapshot.data;
      if (
        isDefined(routeData) &&
        typeof routeData['nestedContentScrollable'] === 'boolean'
      ) {
        return routeData['nestedContentScrollable'];
      }
      return false; // Default to false
    };

    // Set initial state
    this.isContentScrollable.set(getScrollableState(this.activatedRoute));
    this.cdr.detectChanges();

    // Subscribe to subsequent navigation events
    this.router.events
      .pipe(
        filter(
          (event): event is NavigationEnd => event instanceof NavigationEnd,
        ),
        map(() => getScrollableState(this.activatedRoute)),
        takeUntilDestroyed(this.destroyRef),
      )
      .subscribe((scrollableValue: boolean) => {
        if (this.isContentScrollable() !== scrollableValue) {
          this.isContentScrollable.set(scrollableValue);
          this.cdr.detectChanges();
        }
      });
  }

